const data = $('InfluxDB: Verbrauch abfragen').first()?.json ?? {};
const profileRaw = $('InfluxDB: Lastprofil abfragen').first()?.json ?? {};
const stateRaw = $('evcc: State abrufen').first()?.json ?? {};
const tariffRaw = $('evcc: Tarif abrufen').first()?.json ?? {};
const series = data?.results?.[0]?.series?.[0]?.values ?? [];

const tomorrow = new Date();
tomorrow.setDate(tomorrow.getDate() + 1);
const targetWeekday = tomorrow.getDay();

const sameWeekday = series
  .filter(([time, kwh]) => new Date(time).getDay() === targetWeekday && kwh > 1)
  .map(([, kwh]) => kwh);
const allDays = series.filter(([, kwh]) => kwh > 1).map(([, kwh]) => kwh);
const values = sameWeekday.length >= 2 ? sameWeekday : allDays;
const avg = values.length > 0 ? values.reduce((a, b) => a + b, 0) / values.length : 10;
const source = sameWeekday.length >= 2 ? 'gleicher Wochentag' : allDays.length > 0 ? 'Gesamtdurchschnitt' : 'Fallback';
const avgRounded = Math.round(avg * 10) / 10;
const dataDays = sameWeekday.length || allDays.length;

// evcc State
const evccState = stateRaw?.result ?? stateRaw;
const soc = parseFloat(evccState?.batterySoc ?? 50);
const availableCapacity = Math.round((1 - soc / 100) * 7.6 * 10) / 10;
const loadpoints = evccState?.loadpoints ?? [];

// Solar forecast tomorrow
const forecastData = evccState?.forecast?.solar?.tomorrow ?? evccState?.pvForecast?.tomorrow ?? [];
const solarTomorrow = Array.isArray(forecastData)
  ? Math.round(forecastData.reduce((s, h) => s + (h.wh ?? h.energy ?? 0), 0) / 1000 * 10) / 10
  : Math.round((parseFloat(forecastData) || 0) * 10) / 10;

// EV/Wallbox info
let evSection = '';
const presentLPs = loadpoints.filter(lp => lp.vehiclePresent);
if (presentLPs.length > 0) {
  const info = presentLPs.map(lp => {
    const parts = [];
    if (lp.planEnergy) parts.push('Ladeenergie: ' + lp.planEnergy + ' kWh');
    if (lp.planTime) parts.push('bis: ' + lp.planTime);
    return parts.length ? parts.join(', ') : 'Fahrzeug angeschlossen';
  }).join(' | ');
  evSection = '\nFahrzeug(e): ' + info + '\nAddiere EV-Energiebedarf zum Tagesverbrauch.';
}

// Tibber rates for tomorrow
const rates = tariffRaw?.result?.rates ?? tariffRaw?.rates ?? [];
const tmrStart = new Date(); tmrStart.setDate(tmrStart.getDate() + 1); tmrStart.setHours(0,0,0,0);
const tmrEnd = new Date(tmrStart); tmrEnd.setDate(tmrEnd.getDate() + 1);
const tomorrowRates = rates
  .filter(r => new Date(r.start) >= tmrStart && new Date(r.start) < tmrEnd)
  .sort((a, b) => new Date(a.start) - new Date(b.start));

const getPrice = r => r?.value ?? r?.price;
const validRates = tomorrowRates.filter(r => {
  const p = getPrice(r);
  return p !== undefined && p !== null && !isNaN(p);
});
const tariffStr = validRates.length > 0
  ? validRates.map(r => {
      const h = new Date(r.start).getHours().toString().padStart(2, '0');
      const ct = Math.round(getPrice(r) * 10000) / 100;
      return h + ':00: ' + ct + 'ct';
    }).join(' | ')
  : tomorrowRates.length > 0
    ? 'Tarif-Daten vorhanden aber Preisfeld fehlt (Struktur: ' + JSON.stringify(Object.keys(tomorrowRates[0])) + ')'
    : 'keine Tarif-Daten';

// Load profile
const offsetHours = -new Date().getTimezoneOffset() / 60;
const byHour = {};
for (let h = 0; h < 24; h++) byHour[h] = [];
const profileSeries = profileRaw?.results?.[0]?.series?.[0]?.values ?? [];
profileSeries
  .filter(([time]) => new Date(time).getDay() === targetWeekday)
  .forEach(([time, kwh]) => {
    const local = new Date(new Date(time).getTime() + offsetHours * 3600000);
    const hour = local.getHours();
    if (kwh !== null && kwh > 0) byHour[hour].push(kwh);
  });
const profile = [];
for (let h = 0; h < 24; h++) {
  const vals = byHour[h];
  profile.push({ hour: h, avg_kwh: vals.length > 0 ? Math.round(vals.reduce((a,b)=>a+b,0)/vals.length*100)/100 : 0, samples: vals.length });
}
const profileDays = Math.max(...profile.map(p => p.samples), 0);
const profileSection = profileDays >= 4
  ? '\n\nStündliches Verbrauchsprofil (gleicher Wochentag, ' + profileDays + ' Messtage):\n' +
    profile.map(p => p.hour.toString().padStart(2,'0') + ':00: ' + p.avg_kwh + ' kWh').join(' | ') +
    '\n\nStunden mit hohem Verbrauch einplanen.'
  : '';

const prompt = 'Optimiere die Batterieladekosten fuer morgen.' +
  '\n\nAktuelle Daten:' +
  '\nBatterie: SoC ' + soc + '%, verfuegbare Kapazitaet: ' + availableCapacity + ' kWh' +
  '\nSolar-Prognose morgen: ' + solarTomorrow + ' kWh' +
  '\nErwarteter Tagesverbrauch: ' + avgRounded + ' kWh (' + source + ', ' + dataDays + ' Messtage)' +
  evSection +
  '\n\nTibber-Preise morgen:\n' + tariffStr +
  profileSection +
  '\n\nBerechne den optimalen Preisschwellwert:' +
  '\n- Energiebedarf = ' + avgRounded + ' - ' + solarTomorrow + ' (Solar) - ' + availableCapacity + ' (Batterie) kWh' +
  '\n- Wenn Bedarf <= 0: threshold_ct = 0 (Solar + Batterie reichen)' +
  '\n- Wenn Bedarf > 0: waehle guenstigste Tibber-Slots bis Bedarf gedeckt, Schwellwert = hoechster Slot-Preis x 1.05' +
  '\n- n8n setzt den Schwellwert – mache KEINEN evcc-API-Aufruf' +
  '\n\nAntworte NUR mit JSON: { "threshold_ct": <Zahl in ct/kWh>, "reasoning": "<kurze Begruendung>" }';

return [{ json: { avg_consumption_kwh: avgRounded, data_days: dataDays, source, soc, solar_tomorrow_kwh: solarTomorrow, prompt } }];

// Alle möglichen Pfade für die Claude-Antwort probieren
  const item = $input.first() ?? $input.item;
  const data = item?.json ?? {};

  const response = data.output
    ?? data.text
    ?? data.message
    ?? data.content
    ?? JSON.stringify(data);

  let threshold = null;
  let reasoning = 'Keine Begründung';

  // Versuche JSON-Block zu extrahieren (letzten Block bevorzugen, keine verschachtelten Klammern)
  const allMatches = [...String(response).matchAll(/\{[^{}]*"threshold_ct"[^{}]*\}/g)];
  const jsonMatch = allMatches.length > 0 ? allMatches[allMatches.length - 1][0] : null;
  if (jsonMatch) {
    try {
      const parsed = JSON.parse(jsonMatch);
      threshold = parseFloat(parsed.threshold_ct);
      reasoning = parsed.reasoning ?? reasoning;
    } catch(e) {}
  }

  // Fallback: Zahl nach threshold_ct suchen
  if (threshold === null) {
    const numMatch = String(response).match(/threshold_ct["' ]*[:=]["' ]*(\d+\.?\d*)/);
    if (numMatch) threshold = parseFloat(numMatch[1]);
  }

  // Wenn nichts gefunden: Debug-Info ausgeben statt crash
  if (threshold === null || isNaN(threshold)) {
    return [{ json: {
      error: true,
      debug_response: String(response).slice(0, 1000),
      debug_keys: Object.keys(data).join(', ')
    }}];
  }

  threshold = Math.min(50, Math.max(0, threshold));

  return [{ json: {
    threshold_ct: threshold,
    reasoning,
    timestamp: new Date().toISOString()
  }}];

const usage = $('Claude Sonnet + evcc MCP').first()?.json?.tokenUsage ?? {};
const inputTokens = usage.inputTokens ?? usage.prompt_tokens ?? 4500;
const outputTokens = usage.outputTokens ?? usage.completion_tokens ?? 500;
const cost_usd = (inputTokens / 1000000 * 3) + (outputTokens / 1000000 * 15);
const costRounded = Math.round(cost_usd * 100000) / 100000;
return [{ json: {
  workflow: 'daily',
  input_tokens: inputTokens,
  output_tokens: outputTokens,
  cost_usd: costRounded,
  timestamp: new Date().toISOString(),
  line_protocol: 'ai_costs,workflow=daily input_tokens=' + inputTokens + 'i,output_tokens=' + outputTokens + 'i,cost_usd=' + costRounded
}}];

const now = new Date();
const todayUTC = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate())).toISOString();
const monthUTC = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), 1)).toISOString();
return [{ json: {
  today_utc: todayUTC,
  month_utc: monthUTC,
  query_today: 'SELECT sum("cost_usd") FROM "ai_costs" WHERE time >= \'' + todayUTC + '\'',
  query_month: 'SELECT sum("cost_usd") FROM "ai_costs" WHERE time >= \'' + monthUTC + '\''
}}];
